    var ADDS = [{"p":"PART 1. 수정신고","q":[{"answer":"X","text":"납기 후의 과세표준 신고서를 제출한 자는 과세표준 수정신고서를 제출할 수 없다.","exp":"\"제출할 수 없다\"가 틀렸다. 법정신고기한까지 신고한 자뿐 아니라 기한후(납기 후) 과세표준신고서를 제출한 자도 수정신고서를 제출할 수 있다. 일단 신고서를 낸 자는 그 신고를 고칠 수 있기 때문이며, 고칠 원본이 없는 무신고자만 수정신고를 할 수 없다.","src":"2021 지방직 9급"},{"answer":"O","text":"과세표준 신고서를 법정신고기한까지 제출한 자의 수정신고는 당초의 신고에 따라 확정된 과세표준과 세액을 증액하여 확정하는 효력을 가진다.","exp":"법정신고기한까지 신고한 자의 수정신고는 그 자체로 당초 확정된 과세표준·세액을 증액하여 확정하는 효력을 가진다. 스스로 세액을 확정시키는 수정신고와 달리, 경정청구는 확정력 없이 지자체장의 결정을 거쳐야 한다는 점과 대비된다.","src":"2021 지방직 9급"},{"answer":"X","text":"과세표준 신고서를 법정신고기한까지 제출한 자의 수정신고는 당초의 신고에 따라 확정된 과세표준과 세액을 감액하여 확정하는 효력을 가진다.","exp":"\"감액하여\"가 틀렸다. 수정신고는 증액하여 확정하는 효력을 가진다. 세액을 감액받으려는 경우는 수정신고가 아니라 경정청구에 의하여야 하므로 수정신고에 감액확정 효력은 존재하지 않는다."}],"tb":[{"k":"sec","t":"1-6. 수정신고의 효력 — 증액확정"},{"k":"p","t":"법정신고기한까지 과세표준신고서를 제출한 자의 수정신고는 당초의 신고에 따라 확정된 과세표준과 세액을 증액하여 확정하는 효력을 가진다. 즉 수정신고는 그 자체로 세액을 확정시키므로, 별도의 정부 결정을 기다릴 필요가 없다."},{"k":"note","v":"box","title":"💡 경정청구와의 대비","t":"경정청구는 \"돌려달라\"는 요청일 뿐 그 자체로 세액을 확정하지 못하고 지자체장의 결정(청구받은 날부터 2개월 이내)을 거쳐야 한다. 스스로 세액을 확정시키는 수정신고와 방향·효력이 모두 반대다."}],"wi":["📝 \"수정신고는 당초 확정된 세액을 감액하여 확정하는 효력을 가진다\" → ❌ 증액하여 확정하는 효력이다. 감액 방향은 언제나 경정청구의 몫."]},{"p":"PART 2. 경정 등의 청구","q":[{"answer":"X","text":"조세조약에 따른 상호합의가 경정의 내용과 다르게 이루어졌을 때에는 그 사유가 발생한 날부터 90일 이내에 경정을 청구할 수 있다.","exp":"\"그 사유가 발생한 날부터\"가 틀렸다. 조세조약에 따른 상호합의가 다르게 이루어진 것은 후발적 사유이므로 그 사유가 발생한 것을 안 날부터 90일 이내에 청구해야 한다. 사유가 생겨도 납세자가 모르면 기간이 시작되지 않는다.","src":"2021 지방직 9급"},{"answer":"O","text":"「지방세기본법」 또는 지방세관계법에 따른 과세표준 신고서를 법정신고기한까지 제출한 자뿐만 아니라 납기 후의 과세표준 신고서를 제출한 자도 경정청구를 할 수 있는 자에 해당한다.","exp":"경정청구권자에는 법정신고기한 내 신고자뿐 아니라 기한후(납기 후)신고서를 제출한 자도 포함된다. 다만 아예 신고서를 내지 않은 무신고자는 고칠 신고가 없어 일반 경정청구를 할 수 없다는 점과 구별한다.","src":"2021 지방직 9급"}],"tb":[],"wi":[]}];
